export type GitSource = GithubSource | GitlabSource | GitProxySource;
export type GitSourceType = 'github' | 'gitlab' | 'git-proxy';
type GitSourceBase = {
    type: GitSourceType;
    owner: string;
    repo: string;
    deployBranch: string;
    contentDirectory: string;
    isPrivate: boolean;
};
export type GitProxyAuthMethodType = 'iam-role-assumption';
export type GitProxySigningMethod = GitProxySigV4SigningMethod;
export type GitProxySigV4SigningMethod = {
    type: 'sigv4';
    region: string;
    service: string;
};
export type GitProxyAuthMethod = GitProxyIamRoleAssumptionAuth;
export type GitProxyIamRoleAssumptionAuth = {
    type: 'iam-role-assumption';
    roleArnChain: Record<number, string>;
};
export type GithubSource = {
    type: 'github';
} & GitSourceBase;
export type GitlabSource = {
    type: 'gitlab';
    projectId: number;
    hostUrl?: string;
} & GitSourceBase;
export type GitProxySource = {
    type: 'git-proxy';
    package: string;
    authMethod: GitProxyAuthMethod;
    signingMethod?: GitProxySigningMethod;
    hostUrl: string;
    supportsGetContent?: boolean;
} & GitSourceBase;
export {};
